def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache: Dict[frozenset, float] = {}
    # Marginal contribution cache
    contrib_cache: Dict[Tuple[int, frozenset], float] = {}

    def compute_hv(indices: Set[int]) -> float:
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices), :]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    def marginal_contrib(idx: int, base_set: Set[int]) -> float:
        key = (idx, frozenset(base_set))
        if key in contrib_cache:
            return contrib_cache[key]
        if idx in base_set:
            contrib = compute_hv(base_set) - compute_hv(base_set - {idx})
        else:
            contrib = compute_hv(base_set | {idx}) - compute_hv(base_set)
        contrib_cache[key] = contrib
        return contrib

    # 1. Greedy initialization
    current = set()
    for _ in range(k):
        best_idx = -1
        best_gain = -float('inf')
        for idx in range(n):
            if idx not in current:
                gain = marginal_contrib(idx, current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
        if best_idx != -1:
            current.add(best_idx)

    # 2. Evolutionary search with adaptive mutation
    pop_size = 20
    population: List[Tuple[Set[int], float, int]] = [(current, compute_hv(current), k)]

    # Initialize population with greedy and random solutions
    for _ in range(pop_size - 1):
        size = random.randint(max(1, k - 2), min(n, k + 2))
        indices = set(random.sample(range(n), size))
        hv = compute_hv(indices)
        population.append((indices, hv, size))

    # Pareto archive: (solution, hv, size)
    archive: List[Tuple[Set[int], float, int]] = []

    max_generations = 40
    for gen in range(max_generations):
        # Environmental selection: keep best by HV, break ties by size closeness to k
        population.sort(key=lambda x: (-x[1], abs(x[2] - k)))
        population = population[:pop_size]

        # Update Pareto archive (non-dominated by HV and size)
        for sol, hv, sz in population:
            dominated = False
            for a_sol, a_hv, a_sz in archive:
                if a_hv >= hv and a_sz <= sz and (a_hv > hv or a_sz < sz):
                    dominated = True
                    break
            if not dominated:
                # Remove solutions dominated by new one
                archive = [a for a in archive if not (hv >= a[1] and sz <= a[2] and (hv > a[1] or sz < a[2]))]
                archive.append((sol.copy(), hv, sz))
        # Keep archive bounded
        if len(archive) > pop_size:
            archive.sort(key=lambda x: (-x[1], abs(x[2] - k)))
            archive = archive[:pop_size]

        # Generate offspring
        offspring = []
        for _ in range(pop_size // 2):
            # Tournament selection
            idx1, idx2 = random.sample(range(len(population)), 2)
            parent1 = population[idx1][0]
            parent2 = population[idx2][0]

            # Uniform crossover
            child = set()
            for i in range(n):
                if random.random() < 0.5:
                    if i in parent1:
                        child.add(i)
                else:
                    if i in parent2:
                        child.add(i)

            # Adaptive mutation based on size deviation
            size_dev = abs(len(child) - k)
            mutation_rate = 0.4 / (1.0 + size_dev)

            # Contribution-guided mutation
            if random.random() < mutation_rate:
                if len(child) > 0 and random.random() < 0.5:
                    # Remove worst contributor
                    worst_idx = None
                    worst_contrib = float('inf')
                    for idx in child:
                        contrib = marginal_contrib(idx, child - {idx})
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx
                    if worst_idx is not None:
                        child.remove(worst_idx)

                if len(child) < n and random.random() < 0.5:
                    # Add best contributor
                    best_idx = None
                    best_gain = -float('inf')
                    for idx in range(n):
                        if idx not in child:
                            gain = marginal_contrib(idx, child)
                            if gain > best_gain:
                                best_gain = gain
                                best_idx = idx
                    if best_idx is not None:
                        child.add(best_idx)

            # Ensure size exactly k
            while len(child) > k:
                # Remove smallest contributor
                worst_idx = None
                worst_contrib = float('inf')
                for idx in child:
                    contrib = marginal_contrib(idx, child - {idx})
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx
                if worst_idx is not None:
                    child.remove(worst_idx)

            while len(child) < k:
                # Add largest contributor
                best_idx = None
                best_gain = -float('inf')
                for idx in range(n):
                    if idx not in child:
                        gain = marginal_contrib(idx, child)
                        if gain > best_gain:
                            best_gain = gain
                            best_idx = idx
                if best_idx is not None:
                    child.add(best_idx)

            hv = compute_hv(child)
            offspring.append((child, hv, len(child)))

        population.extend(offspring)

    # 3. Select best solution of size k
    candidates = [sol for sol, hv, sz in population + archive if sz == k]
    if not candidates:
        candidates = [sol for sol, hv, sz in population + archive]

    best_set = max(candidates, key=lambda s: compute_hv(s))

    # 4. Deterministic contribution-swap local refinement
    improved = True
    max_iters = 15
    iter_count = 0
    while improved and iter_count < max_iters:
        improved = False
        current_hv = compute_hv(best_set)

        # Compute contributions for all points
        contrib_in = {}
        for idx in best_set:
            contrib_in[idx] = marginal_contrib(idx, best_set - {idx})

        contrib_out = {}
        for idx in set(range(n)) - best_set:
            contrib_out[idx] = marginal_contrib(idx, best_set)

        # Sort: worst inside, best outside
        worst_inside = sorted(contrib_in.items(), key=lambda x: x[1])[:3]
        best_outside = sorted(contrib_out.items(), key=lambda x: x[1], reverse=True)[:3]

        # Try swaps
        for w_idx, w_contrib in worst_inside:
            for b_idx, b_contrib in best_outside:
                new_set = (best_set - {w_idx}) | {b_idx}
                new_hv = compute_hv(new_set)
                if new_hv > current_hv:
                    best_set = new_set
                    improved = True
                    break
            if improved:
                break

        iter_count += 1

    # Final size adjustment (should be k already, but ensure)
    if len(best_set) > k:
        # Remove smallest contributors
        contribs = [(marginal_contrib(idx, best_set - {idx}), idx) for idx in best_set]
        contribs.sort()
        best_set = set(idx for _, idx in contribs[:k])
    elif len(best_set) < k:
        # Add largest contributors
        current = best_set.copy()
        while len(current) < k:
            best_idx = None
            best_gain = -float('inf')
            for idx in range(n):
                if idx not in current:
                    gain = marginal_contrib(idx, current)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
        best_set = current

    return points[list(best_set), :]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache: Dict[frozenset, float] = {}
    contrib_cache: Dict[Tuple[frozenset, int], float] = {}

    def compute_hv(indices: Set[int]) -> float:
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        selected = points[list(indices)]
        hv = pg.hypervolume(selected)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    def marginal_contribution(S: Set[int], p: int) -> float:
        key = (frozenset(S), p)
        if key in contrib_cache:
            return contrib_cache[key]
        if p in S:
            contrib = compute_hv(S) - compute_hv(S - {p})
        else:
            contrib = compute_hv(S | {p}) - compute_hv(S)
        contrib_cache[key] = contrib
        return contrib

    # 1. Greedy initialization
    def greedy_init() -> Set[int]:
        current = set()
        for _ in range(k):
            best_contrib = -float('inf')
            best_p = -1
            for p in range(n):
                if p in current:
                    continue
                contrib = marginal_contribution(current, p)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_p = p
            current.add(best_p)
        return current

    # 2. Pareto archive (size -> (solution, hv))
    archive: Dict[int, Tuple[Set[int], float]] = {}
    def update_archive(sol: Set[int]):
        size = len(sol)
        hv = compute_hv(sol)
        if size not in archive or hv > archive[size][1]:
            archive[size] = (sol.copy(), hv)

    # 3. Evolutionary search
    pop = [greedy_init()]
    update_archive(pop[0])
    pop_size = 10
    generations = 20

    for gen in range(generations):
        new_pop = []
        for sol in pop:
            size_dev = abs(len(sol) - k)
            mut_rate = 0.2 + 0.3 * (size_dev / max(k, n - k))

            if random.random() < mut_rate:
                child = sol.copy()
                # Add best outside
                candidates = [p for p in range(n) if p not in child]
                if candidates:
                    best_add = max(candidates, key=lambda p: marginal_contribution(child, p))
                    child.add(best_add)
                # Remove worst inside
                if len(child) > 1:
                    worst_in = min(child, key=lambda p: marginal_contribution(child - {p}, p))
                    child.remove(worst_in)
                # Size correction
                while len(child) > k + 2 and len(child) > 1:
                    worst = min(child, key=lambda p: marginal_contribution(child - {p}, p))
                    child.remove(worst)
                while len(child) < max(1, k - 2):
                    candidates = [p for p in range(n) if p not in child]
                    if candidates:
                        best = max(candidates, key=lambda p: marginal_contribution(child, p))
                        child.add(best)
                update_archive(child)
                new_pop.append(child)

        # Environmental selection
        pop = []
        size_best = {}
        for sol in new_pop:
            size = len(sol)
            hv = compute_hv(sol)
            if size not in size_best or hv > size_best[size][1]:
                size_best[size] = (sol, hv)
        pop = [sol for sol, _ in size_best.values()]
        # Fill with archive solutions near k
        while len(pop) < pop_size:
            cand_sizes = [s for s in archive.keys() if abs(s - k) <= 2]
            if cand_sizes:
                size = random.choice(cand_sizes)
                pop.append(archive[size][0].copy())
            else:
                pop.append(greedy_init())

    # 4. Deterministic swap refinement
    best_sol = None
    best_hv = -float('inf')
    for size, (sol, hv) in archive.items():
        if abs(size - k) <= 2 and hv > best_hv:
            best_sol, best_hv = sol, hv
    if best_sol is None:
        best_sol = greedy_init()
        best_hv = compute_hv(best_sol)

    # Adjust to exact size k
    while len(best_sol) < k:
        candidates = [p for p in range(n) if p not in best_sol]
        if not candidates:
            break
        best = max(candidates, key=lambda p: marginal_contribution(best_sol, p))
        best_sol.add(best)
    while len(best_sol) > k:
        worst = min(best_sol, key=lambda p: marginal_contribution(best_sol - {p}, p))
        best_sol.remove(worst)

    # Local swap
    improved = True
    while improved:
        improved = False
        in_contrib = {p: marginal_contribution(best_sol - {p}, p) for p in best_sol}
        out_contrib = {p: marginal_contribution(best_sol, p) for p in range(n) if p not in best_sol}
        sorted_in = sorted(in_contrib.items(), key=lambda x: x[1])
        sorted_out = sorted(out_contrib.items(), key=lambda x: x[1], reverse=True)
        for p_in, c_in in sorted_in[:3]:
            for p_out, c_out in sorted_out[:3]:
                if c_out <= c_in:
                    break
                new_sol = (best_sol - {p_in}) | {p_out}
                new_hv = compute_hv(new_sol)
                if new_hv > best_hv:
                    best_sol, best_hv = new_sol, new_hv
                    improved = True
                    break
            if improved:
                break

    return points[list(best_sol)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache: Dict[frozenset, float] = {}

    def compute_hv(indices_set: Set[int]) -> float:
        """Compute hypervolume for a set of indices"""
        if not indices_set:
            return 0.0

        key = frozenset(indices_set)
        if key in hv_cache:
            return hv_cache[key]

        selected = points[list(indices_set)]
        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S"""
        if p in S:
            S_without = S - {p}
            return compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            return compute_hv(S_with) - compute_hv(S)

    # Pareto archive: store solutions of different sizes
    pareto_archive: Dict[int, Set[int]] = {}

    # 1. Greedy initialization
    def greedy_initialization() -> Set[int]:
        """Fast greedy construction using marginal contributions"""
        current_set = set()

        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')

            for idx in range(n):
                if idx in current_set:
                    continue
                contrib = marginal_contribution(current_set, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx != -1:
                current_set.add(best_idx)

        pareto_archive[k] = current_set
        return current_set

    # 2. Evolutionary search with adaptive mutation
    def evolutionary_search(base_solution: Set[int], generations: int = 15) -> Set[int]:
        """Evolutionary search with size-biased mutation"""
        population_size = 10
        population: List[Set[int]] = [base_solution.copy()]
        population_hv = [compute_hv(base_solution)]

        # Initialize population with mutated solutions
        for i in range(population_size - 1):
            mutated = base_solution.copy()

            # Adaptive mutation rate based on size deviation
            current_size = len(mutated)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.4 * (1 - size_deviation)  # Higher rate when size is far from k

            if random.random() < mutation_rate:
                # Biased mutation: remove worst, add best by contribution
                if len(mutated) > 0:
                    # Remove worst point
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in mutated:
                        contrib = marginal_contribution(mutated - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        mutated.remove(worst_idx)

                # Add best point
                best_contrib = -float('inf')
                best_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                if best_idx is not None:
                    mutated.add(best_idx)

            # Ensure size is exactly k
            while len(mutated) > k:
                # Remove point with smallest contribution
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in mutated:
                    contrib = marginal_contribution(mutated - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    mutated.remove(remove_idx)

            while len(mutated) < k:
                # Add point with largest contribution
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    mutated.add(add_idx)

            population.append(mutated)
            population_hv.append(compute_hv(mutated))

        # Evolutionary generations
        for gen in range(generations):
            # Tournament selection
            tournament_indices = random.sample(range(population_size), 3)
            parent_idx = tournament_indices[0]
            for idx in tournament_indices:
                if population_hv[idx] > population_hv[parent_idx]:
                    parent_idx = idx

            parent = population[parent_idx]

            # Create offspring with size-biased mutation
            offspring = parent.copy()
            current_size = len(offspring)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.3 * (1 - size_deviation)

            if random.random() < mutation_rate:
                # Contribution-guided swap
                if len(offspring) > 0:
                    # Remove worst
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in offspring:
                        contrib = marginal_contribution(offspring - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        offspring.remove(worst_idx)

                    # Add best
                    best_contrib = -float('inf')
                    best_idx = None
                    for idx in range(n):
                        if idx not in offspring:
                            contrib = marginal_contribution(offspring, idx)
                            if contrib > best_contrib:
                                best_contrib = contrib
                                best_idx = idx

                    if best_idx is not None:
                        offspring.add(best_idx)

            # Size correction
            while len(offspring) > k:
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in offspring:
                    contrib = marginal_contribution(offspring - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    offspring.remove(remove_idx)

            while len(offspring) < k:
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in offspring:
                        contrib = marginal_contribution(offspring, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    offspring.add(add_idx)

            offspring_hv = compute_hv(offspring)

            # Replace worst in population
            worst_idx = np.argmin(population_hv)
            if offspring_hv > population_hv[worst_idx]:
                population[worst_idx] = offspring
                population_hv[worst_idx] = offspring_hv

            # Update Pareto archive
            if offspring_hv > compute_hv(pareto_archive.get(k, set())):
                pareto_archive[k] = offspring

        # Return best solution
        best_idx = np.argmax(population_hv)
        return population[best_idx]

    # 3. Contribution-guided local swap refinement
    def local_swap_refinement(solution: Set[int], max_iter: int = 20) -> Set[int]:
        """Local refinement using contribution-guided swaps"""
        current_set = solution.copy()
        current_hv = compute_hv(current_set)

        for _ in range(max_iter):
            improved = False

            # Try swapping worst point with best external point
            worst_contrib = float('inf')
            worst_idx = None
            for idx in current_set:
                contrib = marginal_contribution(current_set - {idx}, idx)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx

            if worst_idx is None:
                break

            best_external_contrib = -float('inf')
            best_external_idx = None
            for idx in range(n):
                if idx not in current_set:
                    contrib = marginal_contribution(current_set - {worst_idx}, idx)
                    if contrib > best_external_contrib:
                        best_external_contrib = contrib
                        best_external_idx = idx

            if best_external_idx is not None:
                new_set = (current_set - {worst_idx}) | {best_external_idx}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    current_set = new_set
                    current_hv = new_hv
                    improved = True

            if not improved:
                break

        return current_set

    # Main algorithm flow
    greedy_solution = greedy_initialization()
    evolved_solution = evolutionary_search(greedy_solution)
    final_solution = local_swap_refinement(evolved_solution)

    return points[list(final_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache = {}
    contrib_cache = {}

    def compute_hv(indices):
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices), :]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    def marginal_contrib(idx, base_set):
        key = (idx, frozenset(base_set))
        if key in contrib_cache:
            return contrib_cache[key]
        contrib = compute_hv(base_set | {idx}) - compute_hv(base_set)
        contrib_cache[key] = contrib
        return contrib

    # 1. Greedy initialization with caching
    current = set()
    for _ in range(k):
        best_idx = None
        best_gain = -float('inf')
        for idx in range(n):
            if idx not in current:
                gain = marginal_contrib(idx, current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
        if best_idx is not None:
            current.add(best_idx)

    # 2. Evolutionary population with Pareto archive
    population = [(current, compute_hv(current), len(current))]
    pop_size = 40
    archive = []

    for _ in range(pop_size - 1):
        size = random.randint(max(1, k - 3), min(n, k + 3))
        indices = set(random.sample(range(n), size))
        hv = compute_hv(indices)
        population.append((indices, hv, size))

    max_generations = 60
    for gen in range(max_generations):
        # Environmental selection
        population.sort(key=lambda x: (-x[1], x[2]))
