        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    # 1. Greedy initialization with caching
    def greedy_initialization() -> Set[int]:
        current = set()
        for _ in range(k):
            best_gain = -float('inf')
            best_idx = None
            for idx in range(n):
                if idx in current:
                    continue
                temp = current | {idx}
                gain = compute_hv(temp) - compute_hv(current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
        return current

    # 2. Initialize population with greedy and variations
    population = []
    pop_size = 30
    greedy_sol = greedy_initialization()
    population.append((greedy_sol, compute_hv(greedy_sol), len(greedy_sol)))

    for _ in range(pop_size - 1):
        if random.random() < 0.7:
            sol = set(greedy_sol)
            mutation_rate = min(0.3, 1.0 / (2 * k))
            # Remove some points
            if len(sol) > 1:
                for idx in list(sol):
                    if random.random() < mutation_rate:
                        sol.remove(idx)
            # Add points with high contribution
            while len(sol) < k and len(sol) < n:
                available = set(range(n)) - sol
                if not available:
                    break
                best_gain = -float('inf')
                best_idx = None
                candidates = random.sample(list(available), min(10, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)
        else:
            size = random.randint(max(1, k-2), min(k+2, n))
            sol = set(random.sample(range(n), size))

        # Adjust size to near k
        while len(sol) > k:
            worst_idx = None
            worst_contrib = float('inf')
            for idx in list(sol):
                temp = sol - {idx}
                contrib = compute_hv(sol) - compute_hv(temp)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                sol.remove(worst_idx)

        while len(sol) < k and len(sol) < n:
            available = set(range(n)) - sol
            if available:
                best_idx = None
                best_gain = -float('inf')
                candidates = random.sample(list(available), min(15, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)

        population.append((sol, compute_hv(sol), len(sol)))

    # 3. Pareto archive maintenance
    archive = []
    archive_max = 30
    target_size = k

    def update_archive(solution: Set[int], size: int, hv: float):
        nonlocal archive
        dominated = False
        to_remove = []
        for i, (a_sol, a_size, a_hv) in enumerate(archive):
            if a_size == size and abs(a_hv - hv) < 1e-9:
                dominated = True
                break
            size_diff_curr = abs(size - target_size)
            size_diff_arch = abs(a_size - target_size)
            if size_diff_curr <= size_diff_arch and hv >= a_hv and (size_diff_curr < size_diff_arch or hv > a_hv):
                to_remove.append(i)
            elif size_diff_arch <= size_diff_curr and a_hv >= hv and (size_diff_arch < size_diff_curr or a_hv > hv):
                dominated = True
                break
        if not dominated:
            for i in sorted(to_remove, reverse=True):
                archive.pop(i)
            archive.append((solution.copy(), size, hv))
        if len(archive) > archive_max:
            archive.sort(key=lambda x: (abs(x[1] - target_size), -x[2]))
            archive = archive[:archive_max]

    # 4. Evolutionary search with adaptive operators
    max_generations = 50
    temperature = 1.0
    cooling_rate = 0.95

    for gen in range(max_generations):
        # Evaluate and update archive
        for sol, hv, size in population:
            update_archive(sol, size, hv)

        # Environmental selection
        combined = population + archive
        combined.sort(key=lambda x: (abs(x[2] - target_size), -x[1]))
        selected = combined[:pop_size]
        population = [(set(sol), hv, size) for sol, hv, size in selected]

        # Generate offspring
        offspring = []
        for _ in range(pop_size // 2):
            # Tournament selection
            idx1, idx2 = random.sample(range(len(population)), 2)
            parent1 = population[idx1][0]
            parent2 = population[idx2][0]

            # Crossover
            if random.random() < 0.8:
                child = set()
                union_set = parent1 | parent2
                if len(union_set) <= k:
                    child = union_set
                else:
                    contribs = []
                    for idx in union_set:
                        single_set = {idx}
                        contrib = compute_hv(single_set)
                        contribs.append((contrib, idx))
                    contribs.sort(reverse=True)
                    child = {idx for _, idx in contribs[:k]}
            else:
                child = set(parent1)

            # Adaptive mutation based on size deviation
            size_diff = len(child) - k
            mutation_rate = min(0.4, 1.0 / (2 * max(1, len(child))))

            # Contribution-guided mutation
            if child:
                # Remove worst with probability
                if random.random() < mutation_rate and len(child) > 1:
                    worst_idx = None
                    worst_contrib = float('inf')
                    for idx in list(child):
                        temp = child - {idx}
                        contrib = compute_hv(child) - compute_hv(temp)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx
                    if worst_idx is not None:
                        child.remove(worst_idx)

                # Add best with probability
                if random.random() < mutation_rate and len(child) < n:
                    available = set(range(n)) - child
                    if available:
                        best_idx = None
                        best_gain = -float('inf')
                        candidates = random.sample(list(available), min(10, len(available)))
                        for idx in candidates:
                            temp = child | {idx}
                            gain = compute_hv(temp) - compute_hv(child)
                            if gain > best_gain:
                                best_gain = gain
                                best_idx = idx
                        if best_idx is not None:
                            child.add(best_idx)

            # Temperature-controlled random swap
            if random.random() < temperature * 0.2 and len(child) > 0:
                available = set(range(n)) - child
                if available:
                    remove_idx = random.choice(list(child))
                    add_idx = random.choice(list(available))
                    child.remove(remove_idx)
                    child.add(add_idx)

            # Ensure size constraint
            while len(child) > k:
                worst_idx = None
                worst_contrib = float('inf')
                for idx in list(child):
                    temp = child - {idx}
                    contrib = compute_hv(child) - compute_hv(temp)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx
                if worst_idx is not None:
                    child.remove(worst_idx)

            while len(child) < k and len(child) < n:
                available = set(range(n)) - child
                if available:
                    best_idx = None
                    best_gain = -float('inf')
                    candidates = random.sample(list(available), min(15, len(available)))
                    for idx in candidates:
                        temp = child | {idx}
                        gain = compute_hv(temp) - compute_hv(child)
                        if gain > best_gain:
                            best_gain = gain
                            best_idx = idx
                    if best_idx is not None:
                        child.add(best_idx)

            if child:
                hv = compute_hv(child)
                offspring.append((child, hv, len(child)))

        # Simulated annealing acceptance
        for child_sol, child_hv, child_size in offspring:
            # Find worst in population to potentially replace
            population.sort(key=lambda x: (abs(x[2] - target_size), -x[1]))
            worst_sol, worst_hv, worst_size = population[-1]

            # Accept if better or with probability based on temperature
            accept = False
            if child_hv > worst_hv:
                accept = True
            elif temperature > 0.01:
                delta = child_hv - worst_hv
                prob = math.exp(delta / temperature)
                if random.random() < prob:
                    accept = True

            if accept:
                population[-1] = (child_sol, child_hv, child_size)

        # Cool temperature
        temperature *= cooling_rate

    # 5. Final selection and contribution-guided local search
    all_candidates = [sol for sol, _, _ in population + archive]
    all_candidates = list(set([tuple(sorted(s)) for s in all_candidates]))

    best_solution = None
    best_hv = -float('inf')

    for sol_tuple in all_candidates:
        sol = set(sol_tuple)
        hv = compute_hv(sol)
        if hv > best_hv:
            best_hv = hv
            best_solution = sol

    # Local search with contribution-guided swaps
    improved = True
    while improved:
        improved = False
        current_hv = compute_hv(best_solution)

        # Evaluate all possible swaps
        for idx_in in list(best_solution):
            for idx_out in set(range(n)) - best_solution:
                new_set = (best_solution - {idx_in}) | {idx_out}
                new_hv = compute_hv(new_set)
                if new_hv > current_hv:
                    best_solution = new_set
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    # Ensure exactly k points
    best_indices = list(best_solution)
    if len(best_indices) > k:
        # Remove smallest contributors
        while len(best_indices) > k:
            worst_idx = None
            worst_contrib = float('inf')
            for idx in best_indices:
                temp_set = set(best_indices) - {idx}
                contrib = compute_hv(set(best_indices)) - compute_hv(temp_set)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                best_indices.remove(worst_idx)
    elif len(best_indices) < k:
        # Add largest contributors
        current = set(best_indices)
        while len(current) < k:
            available = set(range(n)) - current
            if not available:
                break
            best_idx = None
            best_gain = -float('inf')
            for idx in available:
                temp = current | {idx}
                gain = compute_hv(temp) - compute_hv(current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
                best_indices.append(best_idx)

    return points[best_indices, :]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache: Dict[frozenset, float] = {}

    def compute_hv(indices_set: Set[int]) -> float:
        if not indices_set:
            return 0.0
        key = frozenset(indices_set)
        if key in hv_cache:
            return hv_cache[key]
        selected = points[list(indices_set)]
        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        if p in S:
            S_without = S - {p}
            return compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            return compute_hv(S_with) - compute_hv(S)

    # Phase 1: Greedy seeding
    def greedy_seed() -> Set[int]:
        current = set()
        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')
            for idx in range(n):
                if idx in current:
                    continue
                contrib = marginal_contribution(current, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx
            if best_idx != -1:
                current.add(best_idx)
        return current

    # Phase 2: Evolutionary search with size‑adaptive mutation
    def evolutionary_search(initial: Set[int], generations: int = 20) -> Set[int]:
        pop_size = 10
        population = [initial.copy()]
        # Initialize with mutations
        for i in range(pop_size - 1):
            sol = initial.copy()
            # Adaptive mutation rate based on size deviation
            size_dev = abs(len(sol) - k) / max(k, n - k)
            mut_rate = 0.3 + 0.4 * size_dev  # higher if far from k

            if random.random() < mut_rate:
                if len(sol) > 0 and random.random() < 0.5:
                    # Remove worst
                    worst = min(sol, key=lambda x: marginal_contribution(sol - {x}, x))
                    sol.remove(worst)
                if len(sol) < n and random.random() < 0.5:
                    # Add best
                    candidates = [(idx, marginal_contribution(sol, idx)) 
                                  for idx in range(n) if idx not in sol]
                    if candidates:
                        best = max(candidates, key=lambda x: x[1])[0]
                        sol.add(best)
            # Repair to size k
            while len(sol) > k:
                worst = min(sol, key=lambda x: marginal_contribution(sol - {x}, x))
                sol.remove(worst)
            while len(sol) < k:
                candidates = [(idx, marginal_contribution(sol, idx)) 
                              for idx in range(n) if idx not in sol]
                if candidates:
                    best = max(candidates, key=lambda x: x[1])[0]
                    sol.add(best)
            population.append(sol)

        # Pareto archive: store (solution, hv, size)
        archive: List[Tuple[Set[int], float, int]] = []
        max_archive = 15

        def update_archive(sol_set: Set[int]):
            hv_val = compute_hv(sol_set)
            sz = len(sol_set)
            # Dominance check
            non_dominated = True
            to_remove = []
            for i, (other, ohv, osz) in enumerate(archive):
                if (hv_val >= ohv and sz <= osz) and (hv_val > ohv or sz < osz):
                    to_remove.append(i)
                elif (ohv >= hv_val and osz <= sz) and (ohv > hv_val or osz < sz):
                    non_dominated = False
            for i in reversed(to_remove):
                archive.pop(i)
            if non_dominated:
                archive.append((sol_set.copy(), hv_val, sz))
            if len(archive) > max_archive:
                # Remove one with smallest HV if size >= k, else largest size
                archive.sort(key=lambda x: (-x[1], x[2]))
                archive.pop()

        for sol in population:
            update_archive(sol)

        # Evolution
        for gen in range(generations):
            # Tournament selection
            a, b = random.sample(range(len(population)), 2)
            parent = population[a] if compute_hv(population[a]) > compute_hv(population[b]) else population[b]

            # Mutation
            child = parent.copy()
            size_dev = abs(len(child) - k) / max(k, n - k)
            mut_rate = 0.2 + 0.3 * size_dev

            if random.random() < mut_rate:
                if len(child) > 0 and random.random() < 0.5:
                    worst = min(child, key=lambda x: marginal_contribution(child - {x}, x))
                    child.remove(worst)
                if len(child) < n and random.random() < 0.5:
                    candidates = [(idx, marginal_contribution(child, idx)) 
                                  for idx in range(n) if idx not in child]
                    if candidates:
                        best = max(candidates, key=lambda x: x[1])[0]
                        child.add(best)

            # Repair
            while len(child) > k:
                worst = min(child, key=lambda x: marginal_contribution(child - {x}, x))
                child.remove(worst)
            while len(child) < k:
                candidates = [(idx, marginal_contribution(child, idx)) 
                              for idx in range(n) if idx not in child]
                if candidates:
                    best = max(candidates, key=lambda x: x[1])[0]
                    child.add(best)

            # Replace worst in population
            hv_vals = [compute_hv(s) for s in population]
            worst_idx = np.argmin(hv_vals)
            if compute_hv(child) > hv_vals[worst_idx]:
                population[worst_idx] = child
                update_archive(child)

        # Return best solution of size k from archive
        best = None
        best_hv = -float('inf')
        for sol, hv_val, sz in archive:
            if sz == k and hv_val > best_hv:
                best_hv = hv_val
                best = sol
        if best is None:
            # fallback: best in population
            hv_vals = [compute_hv(s) for s in population]
            best = population[np.argmax(hv_vals)]
        return best

    # Phase 3: Deterministic contribution‑swap refinement
    def swap_refinement(S: Set[int], max_iter: int = 15) -> Set[int]:
        current = S.copy()
        for _ in range(max_iter):
            improved = False
            # Find worst in set
            worst = min(current, key=lambda x: marginal_contribution(current - {x}, x))
            # Find best outside set
            best_out = -1
            best_contrib = -float('inf')
            for idx in range(n):
                if idx in current:
                    continue
                contrib = marginal_contribution(current - {worst}, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_out = idx
            # Swap if beneficial
            if best_out != -1 and best_contrib > marginal_contribution(current - {worst}, worst):
                new_set = (current - {worst}) | {best_out}
                if compute_hv(new_set) > compute_hv(current):
                    current = new_set
                    improved = True
            if not improved:
                break
        return current

    # Execute pipeline
    seed = greedy_seed()
    evolved = evolutionary_search(seed)
    final = swap_refinement(evolved)

    return points[list(final)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume contribution cache
    hv_cache = {}

    def compute_hv(indices):
        """Compute hypervolume for a set of indices, using cache."""
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]

        if not indices:
            hv_cache[key] = 0.0
            return 0.0

        data = points[list(indices), :]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    # 1. Greedy initialization
    current_set = set()
    for _ in range(k):
        best_idx = None
        best_gain = -float('inf')
        for idx in range(n):
            if idx not in current_set:
                temp_set = current_set | {idx}
                gain = compute_hv(temp_set) - compute_hv(current_set)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
        if best_idx is not None:
            current_set.add(best_idx)

    # 2. Evolutionary search with adaptive mutation
    population = [current_set]
    pop_size = 30
    for _ in range(pop_size - 1):
        size = random.randint(max(1, k - 5), min(n, k + 5))
        indices = set(random.sample(range(n), size))
        population.append(indices)

    max_generations = 50
    for gen in range(max_generations):
        # Evaluate population
        evaluated = [(set, compute_hv(set), len(set)) for set in population]
        evaluated.sort(key=lambda x: (-x[1], x[2]))
        population = [e[0] for e in evaluated[:pop_size]]

        offspring = []
        for _ in range(pop_size // 2):
            parent1, parent2 = random.sample(population, 2)
            child = set()
            # Uniform crossover
            for i in range(n):
                if random.random() < 0.5:
                    if i in parent1:
                        child.add(i)
                else:
                    if i in parent2:
                        child.add(i)

            # Adaptive mutation
            child_size = len(child)
            mutation_rate = min(0.3, 1.0 / (2 * child_size))
            if random.random() < mutation_rate and child_size < n:
                # Add mutation
                available = set(range(n)) - child
                if available:
                    child.add(random.choice(list(available)))
            if random.random() < mutation_rate and child_size > 1:
                # Remove mutation
                child.remove(random.choice(list(child)))

            # Adjust size towards k
            while len(child) > k:
                # Remove smallest contributor
                contributions = []
                for idx in child:
                    temp = child - {idx}
                    contrib = compute_hv(child) - compute_hv(temp)
                    contributions.append((contrib, idx))
                contributions.sort()
                child.remove(contributions[0][1])

            while len(child) < k and len(child) < n:
                # Add largest contributor
                best_idx = None
                best_gain = -float('inf')
                available = set(range(n)) - child
                for idx in available:
                    temp = child | {idx}
                    gain = compute_hv(temp) - compute_hv(child)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    child.add(best_idx)

            offspring.append(child)

        population.extend(offspring)

    # 3. Contribution-guided local search
    best_set = population[0]
    improved = True
    while improved:
        improved = False
        # Try swaps
        for idx_in in best_set:
            for idx_out in set(range(n)) - best_set:
                temp_set = best_set - {idx_in} | {idx_out}
                if compute_hv(temp_set) > compute_hv(best_set):
                    best_set = temp_set
                    improved = True
                    break
            if improved:
                break

    # Ensure exactly k points
    final_indices = list(best_set)
    if len(final_indices) > k:
        # Remove smallest contributors
        contributions = []
        for idx in final_indices:
            temp = set(final_indices) - {idx}
            contrib = compute_hv(set(final_indices)) - compute_hv(temp)
            contributions.append((contrib, idx))
        contributions.sort()
        final_indices = [idx for _, idx in contributions[:k]]
    elif len(final_indices) < k:
        # Add largest contributors
        current = set(final_indices)
        for _ in range(k - len(final_indices)):
            best_idx = None
            best_gain = -float('inf')
            available = set(range(n)) - current
            for idx in available:
                temp = current | {idx}
                gain = compute_hv(temp) - compute_hv(current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
                final_indices.append(best_idx)

    return points[final_indices, :]
